export const getListVoiceChatSessionsUrl = (params?: ListVoiceChatSessionsParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/voice-chat/sessions?${stringifiedParams}` : `/api/voice-chat/sessions`
}

